package vm

// This contains definitions of the operations, and a few functions and defintions for using them.
// The comments are auto-generated by `peeking.go`, and shouldn't be edited by hand.

func MakeOp(oc Opcode, args ...uint32) *Operation {
	return &Operation{Opcode: oc, Args: args}
}

type Operation struct {
	Opcode Opcode
	Args   []uint32
}

func (op *Operation) MakeLastArg(loc uint32) {
	op.Args[len(op.Args)-1] = loc
}

type Opcode uint8

// Comments on the opcodes are auto-generated from `operations.md` and so should not be edited by hand.
// The meanings of the operand flavors are also explained in `operations.md`.
